cd /workspace/YatCC && python3 << 'PYEOF'
content = open('task/3/EmitIR.cpp').read()

# Fix UnaryExpr::kNot - should be logical NOT, not bitwise
old_unary = '''llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return mCurIrb->CreateNeg(sub);
    case UnaryExpr::kNot:
      return mCurIrb->CreateNot(sub);
    default:
      ABORT();
  }
}'''

new_unary = '''llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return mCurIrb->CreateNeg(sub);
    case UnaryExpr::kNot:
      // Logical NOT: compare with 0, return i32 0 or 1
      return mCurIrb->CreateZExt(
        mCurIrb->CreateICmpEQ(sub, llvm::ConstantInt::get(sub->getType(), 0)),
        mIntTy);
    default:
      ABORT();
  }
}'''

content = content.replace(old_unary, new_unary)

# Also fix all comparison emits to NOT produce i1 but i32 (since our type system uses i32)
# Actually, LLVM comparisons naturally produce i1. We should not fight this.
# The issue is the branch condition type. Let me check if we can just use the i1 directly.

open('task/3/EmitIR.cpp', 'w').write(content)
print("Fixed UnaryExpr::kNot")
PYEOF
